exercise.solutionCode:
function celsiusToFahrenheit(c) {
    return (c * 9 / 5) + 32;
}

function fahrenheitToCelsius(f) {
    return (f - 32) * 5 / 9;
}

const fResult = celsiusToFahrenheit(100);
const cResult = fahrenheitToCelsius(98.6);

console.log(`100C = ${fResult.toFixed(1)}F`);
console.log(`98.6F = ${cResult.toFixed(1)}C`);

